import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { generateTimetable, downloadTimetable, findFormStreams, } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
class EnrollmentsPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          stream : 'nn',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          fileurl:'',
          data: [],
          streams:[],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findFormStreams(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    streams:response.data,
                });
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }
    
    handleStreamInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, stream: v,});
    }
    handleRunTimetable = () => {
        this.setState({
          ...this.state,
          preload:true,
        });
        generateTimetable(this.state.xtoken, this.state)
        .then((response) => {
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    handleDownloadTimetable = () => {
        this.setState({
          ...this.state,
          preload:true,
        });
        downloadTimetable(this.state.xtoken, this.state)
        .then((response) => {
            if( response.status === 200)
            {
                const url = response.fileurl;
                const link = document.createElement('a');
                link.href = url;
                link.setAttribute('download', 'statement');
                link.setAttribute('target', '_blank');
                link.click();
                this.setState({
                    ...this.state,
                    preload:false,
                    fileurl: response.fileurl,
                    error: '',
                });
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
      return (
        <Page title="Print timetable" breadcrumbs={[{ name: 'Timetable', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Print timetable {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Select stream *</Label>
                      <Input onChange={this.handleStreamInput} value={this.state.stream} defaultValue={this.state.stream} type="select" name="frm">
                        <option value="nn" disabled={true}>Select Stream</option>
                        {this.state.streams.map((stt, idx) => (
                            <option value={stt.id}>{stt.form+stt.name}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={4} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <br></br>
                    <Row>
                        <Col xl={6} lg={12} md={12}>
                            <FormGroup>
                                <Button type="button" onClick={this.handleRunTimetable}>View</Button>
                            </FormGroup>
                        </Col>
                        <Col xl={6} lg={12} md={12}>
                            <FormGroup>
                                <Button type="button" onClick={this.handleDownloadTimetable}>Download</Button>
                            </FormGroup>
                        </Col>
                    </Row>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                <Table responsive>
                    <thead>
                    <tr>
                        <td width={60}><b>Day</b></td>
                        <td><b>Lessons</b></td>
                    </tr>
                    </thead>
                    <tbody>
                    { this.state.data.map((trp, idx) => (
                        <tr key={idx}>
                            <td><span className="heavier">{trp.day.substring(0,3)}</span></td>
                            <td>
                                <tr>
                                    { trp.lessons.map((ls, ky) => (
                                        <td width={120} key={ky}>
                                            <span className="heavier">{ls.time}hrs</span><br></br>
                                            <span className="bending">{ls.sublabel}</span><br></br>
                                            {ls.tlabel}<br></br>
                                            {ls.slabel}
                                        </td>
                                    ))}
                                </tr>
                            </td>
                        </tr>
                    ))}
                    </tbody>
                </Table>
                </CardBody>
              </Card>
            </Col>
          </Row>
        </Page>
      );
    }
}
export default EnrollmentsPage;
